import type {
  AdapterCapabilities,
  AdapterCategory,
  AdapterSubscription,
  ConnectionStatus,
  ExchangeAdapter,
  ExchangeConfig,
  HealthMetrics,
  OHLCVCallback,
  OrderbookCallback,
  StatusCallback,
  TickerCallback,
  TradeCallback,
} from '../../types/adapter';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedSymbol, NormalizedTrade, Timeframe } from '../../types/normalized';
import { createSubscriptionId, parseNumeric, secondsToMs } from '../../normalization/pipeline';
import { RateLimiter, EXCHANGE_RATE_LIMITS } from '../../rate-limiter/rate-limiter';
import { sqrtPriceX96ToPrice } from './uniswap-math';
import type { GraphQLResponse, UniswapPoolData, UniswapPoolHourData, UniswapSwapEvent } from './uniswap-types';

const DEFAULT_SUBGRAPH_URL = 'https://api.thegraph.com/subgraphs/name/uniswap/uniswap-v3';

/** Default polling interval (15 seconds). */
const DEFAULT_POLL_INTERVAL_MS = 15_000;

interface ActiveSubscription {
  readonly id: string;
  readonly symbol: string;
  readonly poolAddress: string;
  readonly type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv' | 'status';
  readonly callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback | StatusCallback;
}

/**
 * Uniswap V3 adapter using The Graph for data access.
 *
 * Uses HTTP polling (no WebSocket). Poll every 15 seconds for swaps,
 * every 60 seconds for hourly candle data.
 *
 * Limitations:
 * - ~45 second latency behind on-chain (block time + indexing)
 * - No native OHLCV at sub-hourly resolution (computed from swaps)
 * - No traditional order book (AMM pool)
 */
export class UniswapV3Adapter implements ExchangeAdapter {
  readonly exchangeId = 'uniswap-v3' as const;
  readonly displayName = 'Uniswap V3';
  readonly category: AdapterCategory = 'dex';
  readonly capabilities: AdapterCapabilities = {
    realtime: true,
    historicalDepth: '30d',
    orderbook: false,
    trades: true,
    ohlcv: true,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: true,
    onChainMetrics: true,
    authenticated: false,
  };

  private config: ExchangeConfig | null = null;
  private subgraphUrl = DEFAULT_SUBGRAPH_URL;
  private rateLimiter: RateLimiter | null = null;
  private readonly subscriptions = new Map<string, ActiveSubscription>();
  private readonly statusCallbacks = new Map<string, StatusCallback>();
  private pollTimer: ReturnType<typeof setInterval> | undefined;
  private pollIntervalMs = DEFAULT_POLL_INTERVAL_MS;
  private connectionState: ConnectionStatus = {
    state: 'disconnected',
    latencyMs: 0,
    messagesPerSecond: 0,
    lastMessageAt: 0,
    reconnectAttempt: 0,
    uptime: 0,
  };
  private connectTime = 0;

  async connect(config: ExchangeConfig): Promise<void> {
    this.config = config;
    if (config.restUrl) {
      this.subgraphUrl = config.restUrl;
    }
    const rateLimitConfig = EXCHANGE_RATE_LIMITS['uniswap-v3'];
    if (rateLimitConfig) {
      this.rateLimiter = new RateLimiter('uniswap-v3', rateLimitConfig);
    }
    this.connectTime = Date.now();
    this.updateState('connected');

    this.pollTimer = setInterval(() => {
      this.pollSubscriptions().catch(() => {
        // Polling errors are non-fatal; will retry next interval
      });
    }, this.pollIntervalMs);
  }

  async disconnect(): Promise<void> {
    if (this.pollTimer !== undefined) {
      clearInterval(this.pollTimer);
      this.pollTimer = undefined;
    }
    this.subscriptions.clear();
    this.statusCallbacks.clear();
    this.rateLimiter?.dispose();
    this.rateLimiter = null;
    this.updateState('disconnected');
  }

  getStatus(): ConnectionStatus {
    return { ...this.connectionState, uptime: this.getUptime() };
  }

  getHealthMetrics(): HealthMetrics {
    const status = this.getStatus();
    const uptimeSeconds = status.uptime;
    const uptimePercent = uptimeSeconds > 0 ? Math.min(100, (uptimeSeconds / uptimeSeconds) * 100) : 0;
    return {
      connected: status.state === 'connected',
      latencyMs: status.latencyMs,
      messagesPerSecond: status.messagesPerSecond,
      uptimePercent,
      lastMessageAt: status.lastMessageAt,
      errorRate: 0,
      circuitBreakerState: 'closed',
    };
  }

  onStatusChange(callback: StatusCallback): AdapterSubscription {
    const id = createSubscriptionId('uniswap-v3', 'status', '_global');
    this.statusCallbacks.set(id, callback);
    return {
      id,
      symbol: '_global',
      type: 'status',
      dispose: () => { this.statusCallbacks.delete(id); },
    };
  }

  subscribeTicker(symbol: string, callback: TickerCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'ticker', callback);
  }

  subscribeOrderbook(symbol: string, _depth: number, callback: OrderbookCallback): AdapterSubscription {
    // AMM pools have no order book -- subscription is a no-op, callback never fires
    return this.addSubscription(symbol, 'orderbook', callback);
  }

  subscribeTrades(symbol: string, callback: TradeCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'trades', callback);
  }

  subscribeOHLCV(symbol: string, _timeframe: Timeframe, callback: OHLCVCallback): AdapterSubscription {
    return this.addSubscription(symbol, 'ohlcv', callback);
  }

  async getCandles(symbol: string, _timeframe: Timeframe, from: number, to: number): Promise<NormalizedOHLCV[]> {
    const poolAddress = this.extractPoolAddress(symbol);
    const fromSec = Math.floor(from / 1000);
    const toSec = Math.floor(to / 1000);

    const query = `{
      poolHourDatas(
        where: { pool: "${poolAddress}", periodStartUnix_gte: ${fromSec}, periodStartUnix_lte: ${toSec} }
        orderBy: periodStartUnix
        orderDirection: asc
        first: 1000
      ) {
        periodStartUnix open high low close volumeUSD txCount
      }
    }`;

    await this.rateLimiter?.acquire();
    const response = await this.executeQuery<{ poolHourDatas: UniswapPoolHourData[] }>(query);

    return response.data.poolHourDatas.map(d => ({
      timestamp: secondsToMs(d.periodStartUnix),
      open: parseNumeric(d.open),
      high: parseNumeric(d.high),
      low: parseNumeric(d.low),
      close: parseNumeric(d.close),
      volume: parseNumeric(d.volumeUSD),
      quoteVolume: parseNumeric(d.volumeUSD),
      tradeCount: parseNumeric(d.txCount),
      closed: true,
    }));
  }

  async getOrderbookSnapshot(_symbol: string, _depth: number): Promise<NormalizedOrderbook> {
    // AMM pools do not have traditional order books
    throw new Error('Order book not available for Uniswap V3 AMM pools');
  }

  async getRecentTrades(symbol: string, limit: number): Promise<NormalizedTrade[]> {
    const poolAddress = this.extractPoolAddress(symbol);
    const query = `{
      swaps(
        where: { pool: "${poolAddress}" }
        orderBy: timestamp
        orderDirection: desc
        first: ${Math.min(limit, 1000)}
      ) {
        id timestamp amount0 amount1 sqrtPriceX96
        transaction { id }
      }
    }`;

    await this.rateLimiter?.acquire();
    const response = await this.executeQuery<{ swaps: UniswapSwapEvent[] }>(query);

    return response.data.swaps.map(swap => {
      const amount0 = parseNumeric(swap.amount0);
      const amount1 = parseNumeric(swap.amount1);
      const price = amount0 !== 0 ? Math.abs(amount1 / amount0) : 0;
      return {
        id: swap.id,
        timestamp: secondsToMs(parseNumeric(swap.timestamp)),
        price,
        quantity: Math.abs(amount0),
        side: amount0 > 0 ? 'buy' as const : 'sell' as const,
        buyerMaker: false,
      };
    });
  }

  async getSymbols(): Promise<NormalizedSymbol[]> {
    const query = `{
      pools(
        first: 100
        orderBy: totalValueLockedUSD
        orderDirection: desc
        where: { totalValueLockedUSD_gt: "100000" }
      ) {
        id token0 { id symbol name decimals } token1 { id symbol name decimals }
        feeTier liquidity sqrtPrice volumeUSD totalValueLockedUSD
      }
    }`;

    await this.rateLimiter?.acquire();
    const response = await this.executeQuery<{ pools: UniswapPoolData[] }>(query);

    return response.data.pools.map(pool => {
      const token0Decimals = parseInt(pool.token0.decimals, 10);
      const token1Decimals = parseInt(pool.token1.decimals, 10);
      const feeTier = parseInt(pool.feeTier, 10);

      return {
        symbol: `${pool.token0.symbol}/${pool.token1.symbol}`,
        base: pool.token0.symbol,
        quote: pool.token1.symbol,
        exchangeSymbol: pool.id,
        exchangeId: 'uniswap-v3' as const,
        type: 'dex-pool' as const,
        pricePrecision: Math.max(token0Decimals, token1Decimals),
        quantityPrecision: token0Decimals,
        minQuantity: 0,
        tickSize: sqrtPriceX96ToPrice(1n, token0Decimals, token1Decimals),
        active: parseNumeric(pool.liquidity) > 0,
        contractAddress: pool.id,
        chain: 'ethereum',
        feeTier,
      };
    });
  }

  private addSubscription(
    symbol: string,
    type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv',
    callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback,
  ): AdapterSubscription {
    const id = createSubscriptionId('uniswap-v3', type, symbol);
    const poolAddress = this.extractPoolAddress(symbol);
    const sub: ActiveSubscription = { id, symbol, poolAddress, type, callback };
    this.subscriptions.set(id, sub);

    return {
      id,
      symbol,
      type,
      dispose: () => { this.subscriptions.delete(id); },
    };
  }

  private async pollSubscriptions(): Promise<void> {
    const tradeSubscriptions = Array.from(this.subscriptions.values()).filter(s => s.type === 'trades');
    for (const sub of tradeSubscriptions) {
      const trades = await this.getRecentTrades(sub.symbol, 10);
      for (const trade of trades) {
        (sub.callback as TradeCallback)(trade);
      }
    }
  }

  private async executeQuery<T>(query: string): Promise<GraphQLResponse<T>> {
    const response = await fetch(this.subgraphUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ query }),
    });

    if (!response.ok) {
      throw new Error(`The Graph query failed: ${response.status} ${response.statusText}`);
    }

    const result = await response.json() as GraphQLResponse<T>;
    if (result.errors && result.errors.length > 0) {
      const firstError = result.errors[0];
      throw new Error(`GraphQL error: ${firstError?.message ?? 'Unknown error'}`);
    }

    return result;
  }

  private extractPoolAddress(symbol: string): string {
    // If the symbol looks like an Ethereum address (0x...), use it directly
    if (symbol.startsWith('0x')) return symbol.toLowerCase();
    // Otherwise, this is a normalized symbol -- pool address must be resolved via getSymbols()
    return symbol.toLowerCase();
  }

  private updateState(state: ConnectionStatus['state'], errorMessage?: string): void {
    this.connectionState = {
      state,
      latencyMs: this.connectionState.latencyMs,
      messagesPerSecond: this.connectionState.messagesPerSecond,
      lastMessageAt: this.connectionState.lastMessageAt,
      errorMessage,
      reconnectAttempt: 0,
      uptime: this.getUptime(),
    };
    for (const callback of this.statusCallbacks.values()) {
      callback(this.connectionState);
    }
  }

  private getUptime(): number {
    if (this.connectTime === 0) return 0;
    return (Date.now() - this.connectTime) / 1000;
  }
}
