/**
 * Uniswap V3 price math utilities.
 *
 * Converts sqrtPriceX96 fixed-point values to human-readable prices,
 * accounting for token decimal differences.
 */

/**
 * Convert a sqrtPriceX96 value to a human-readable price.
 *
 * sqrtPriceX96 encodes sqrt(price) as a Q64.96 fixed-point number.
 * price = (sqrtPriceX96 / 2^96)^2 * 10^(token0Decimals - token1Decimals)
 *
 * @param sqrtPriceX96 - The sqrtPriceX96 value (as bigint or string)
 * @param token0Decimals - Decimal places for token0
 * @param token1Decimals - Decimal places for token1
 * @returns Price of token0 in terms of token1
 */
export function sqrtPriceX96ToPrice(
  sqrtPriceX96: bigint | string,
  token0Decimals: number,
  token1Decimals: number,
): number {
  const sqrtPrice = typeof sqrtPriceX96 === 'string' ? BigInt(sqrtPriceX96) : sqrtPriceX96;
  const Q96 = 2n ** 96n;

  // To avoid precision loss, compute (sqrtPrice * sqrtPrice * 10^token0Decimals) / (Q96 * Q96 * 10^token1Decimals)
  const numerator = sqrtPrice * sqrtPrice * (10n ** BigInt(token0Decimals));
  const denominator = Q96 * Q96 * (10n ** BigInt(token1Decimals));

  // Convert to number with sufficient precision
  // For very large values, divide in steps to maintain precision
  if (denominator === 0n) return 0;

  return Number(numerator) / Number(denominator);
}

/**
 * Convert a human-readable price back to sqrtPriceX96.
 * Inverse of sqrtPriceX96ToPrice.
 *
 * @param price - Human-readable price (token0 in terms of token1)
 * @param token0Decimals - Decimal places for token0
 * @param token1Decimals - Decimal places for token1
 * @returns sqrtPriceX96 as bigint
 */
export function priceToSqrtPriceX96(
  price: number,
  token0Decimals: number,
  token1Decimals: number,
): bigint {
  const Q96 = 2n ** 96n;
  const decimalAdjustment = 10 ** (token1Decimals - token0Decimals);
  const adjustedPrice = price * decimalAdjustment;
  const sqrtPrice = Math.sqrt(adjustedPrice);

  // sqrtPriceX96 = sqrtPrice * 2^96
  return BigInt(Math.round(sqrtPrice * Number(Q96)));
}

/**
 * Determine the price direction for a Uniswap V3 pool.
 * Token ordering in pools follows address sorting, which may invert
 * the expected price direction.
 *
 * @param token0Address - Address of token0 (lower address)
 * @param token1Address - Address of token1 (higher address)
 * @param desiredBaseAddress - Address of the token you want as base
 * @returns true if the price needs to be inverted (1/price)
 */
export function shouldInvertPrice(
  token0Address: string,
  _token1Address: string,
  desiredBaseAddress: string,
): boolean {
  return token0Address.toLowerCase() !== desiredBaseAddress.toLowerCase();
}

/**
 * Calculate the tick spacing for a given fee tier.
 *
 * @param feeTier - Fee tier in hundredths of a bip (100 = 0.01%, 500 = 0.05%, 3000 = 0.30%, 10000 = 1.00%)
 * @returns Tick spacing
 */
export function feeToTickSpacing(feeTier: number): number {
  switch (feeTier) {
    case 100: return 1;
    case 500: return 10;
    case 3000: return 60;
    case 10000: return 200;
    default: return 60;
  }
}

/**
 * Convert a tick value to a price.
 *
 * @param tick - The tick value
 * @param token0Decimals - Decimal places for token0
 * @param token1Decimals - Decimal places for token1
 * @returns Price of token0 in terms of token1
 */
export function tickToPrice(
  tick: number,
  token0Decimals: number,
  token1Decimals: number,
): number {
  const price = 1.0001 ** tick;
  const decimalAdjustment = 10 ** (token0Decimals - token1Decimals);
  return price * decimalAdjustment;
}
